def validate(args, events):
    water = args[0]
    if len(events) != len(water):
        return False
    if events.count("H") != water.count("H") or events.count("O") != water.count("O"):
        return False
    for g in range(0, len(events), 3):
        group = events[g:g + 3]
        if sorted(group) != ["H", "H", "O"]:
            return False
    return True
